export const getMarketData = async () => {
    try {
        // Aracıyı (proxy) kaldırdık, çünkü aracı eski veriyi önbellekte (cache) tutarak yanlış değer gösteriyordu.
        // Artık veriyi doğrudan kaynağından anlık olarak çekecek ve önbelleklemeyi engelleyecek bir zaman damgası kullanıyoruz.
        const targetUrl = `https://finans.truncgil.com/today.json?disableCache=${new Date().getTime()}`;

        const response = await fetch(targetUrl);
        const data = await response.json();

        // İstenilen veriler
        const selected = [
            { key: 'USD', label: 'USD/TRY', prefix: '₺' },
            { key: 'EUR', label: 'EUR/TRY', prefix: '₺' },
            { key: 'ons', label: 'ONS', prefix: '$' },
            { key: 'gram-altin', label: 'GRAM Altın', prefix: '₺' },
            { key: 'ceyrek-altin', label: 'ÇEYREK', prefix: '₺' },
            { key: 'cumhuriyet-altini', label: 'CUMHURİYET', prefix: '₺' }
        ];

        const formattedData = selected.map(item => {
            const rawItem = data[item.key];
            if (!rawItem) return null;

            const trend = rawItem['Değişim'].includes('-') ? 'down' : 'up';

            // Fiyatı formatlama (örnek: "44,8547" -> en fazla iki ondalık hane al veya direkt kullan)
            let rawPrice = rawItem['Satış'];
            // Dolar ise '$' kendi içinde gelebiliyor o yüzden kontrol ediyoruz
            const price = rawPrice.startsWith('$') ? rawPrice : `${item.prefix}${rawPrice}`;

            return {
                symbol: item.label,
                price: price,
                trend: trend
            };
        }).filter(Boolean);

        return formattedData;

    } catch (error) {
        console.error("Canlı veri çekilemedi:", error);
        // Hata durumunda geçici veri
        return [
            { symbol: 'Hata', price: 'Bağlantı Yok', trend: 'down' }
        ];
    }
};
